#!/usr/bin/env python3
"""BULK FETCH — full text for the DEDUPED UNION of the four discovery scouts.

THE ONE DOOR. Every network request goes through acquisition.Acquirer; every set of
recovered bytes is content-addressed and profiled by acquisition.record_manifestation
(== deep_fetch.fetch_text). This file writes NO status and has no API that could: the
per-unit outcome is DERIVED from the ledger by event_ledger's reducers, so a THROTTLE
(429) lands as BACKEND_FAILED -> retriable, and NEVER as "no free copy exists".

ISOLATION (DO NOT COLLIDE): reads the scouts' outputs; writes ONLY under
    outputs/acquisition_campaign/ (fetch_ledger.jsonl, blobs/, fetch_*.json).
It never touches journal_corpus_content.json, evidence_cards_bound.json, or the
composer. The ledger + blob store here are private to this campaign.

POLITENESS (we IP-throttled ourselves overnight): >=1.3s spacing per host (Acquirer),
exponential backoff on 429 (Acquirer), plus a per-host circuit breaker that stops
hammering a host after repeated throttles — recorded as a budget/throttle skip, which
is NOT an evidence gap.

PRIORITY (max the search, not the count): the outline's EMPTY coverage cells
(healthcare, manufacturing, retail, finance, education, agriculture, transport), the
2023-2025 generative-AI frontier, and the hand-verified canon/contrasts come FIRST;
within a tier, a transparent quality blend orders the rest. weighting.py's core rule is
honoured: field-normalized influence is UNKNOWN offline (never 0), and raw citations are
a weak, capped tie-break only — never the ranking key. Everything not reached in the
budget is LOGGED as DEFERRED with a reason. No silent truncation.

    python3 bulk_fetch.py build                       # offline: union + priority + OA harvest
    python3 bulk_fetch.py fetch --max-units N --wall-clock-mins M [--sample K] [--tiers 0,1,2]
    python3 bulk_fetch.py report                       # re-derive outcomes from the ledger
"""
from __future__ import annotations

import argparse
import json
import math
import os
import re
import sys
import time
import urllib.parse
from pathlib import Path

# ── THE TOOLS ON DISK (import, do not rebuild) ───────────────────────────────────────
FLY = '/home/polaris/wt/flywheel/scripts'
sys.path.insert(0, FLY)

# Politeness margin over the 1.1s floor. Set BEFORE importing acquisition (it reads the
# env at import for SPACING_S).
os.environ.setdefault('POLARIS_SPACING', '1.3')

import acquisition  # noqa: E402
from acquisition import Acquirer, BlobStore, open_ledger, content_host  # noqa: E402
import deep_fetch  # noqa: E402
from event_ledger import (  # noqa: E402
    derive_backend_outcome, derive_content_profile, derive_route_status,
    derive_semantic_binding,
    C_FULLTEXT, C_ABSTRACT, C_CITATION, C_NOT_DOC, C_UNREADABLE,
    BACKEND_FAILED, ACCESS_BLOCKED, NOT_INDEXED, RESPONDED, NO_OUTCOME,
    SAME_WORK, VERSION_PUBLISHED, VERSION_PREPRINT, DIFFERENT_WORK,
)

# ── PATHS — everything private to this campaign ──────────────────────────────────────
CAMP = Path('/home/polaris/polaris_project/outputs/acquisition_campaign')
FLY_CAMP = Path('/home/polaris/wt/flywheel/outputs/acquisition_campaign')

M1 = CAMP / 'candidates.json'                       # citation-graph expansion (4,656)
M2 = FLY_CAMP / 'oa_cell_discovery.json'            # empty industry cells (158)
M3 = FLY_CAMP / 'frontier_2023_2025_FINAL.json'     # 2023-2025 frontier (299)
M4 = CAMP / 'canon_and_contrasts_leads.json'        # hand-verified canon/contrasts (29)
POOL_META = CAMP / 'pool_meta.jsonl'                # OpenAlex records w/ OA locations (offline)

LEDGER = CAMP / 'fetch_ledger.jsonl'
BLOBS = CAMP / 'blobs'
UNION_OUT = CAMP / 'fetch_union.json'
RANKED_OUT = CAMP / 'fetch_ranked.json'
OUTCOMES_OUT = CAMP / 'fetch_outcomes.json'
PROGRESS_LOG = CAMP / 'fetch_progress.log'

MAILTO = acquisition.MAILTO

EMPTY_CELLS = {'healthcare', 'manufacturing', 'retail', 'finance',
               'education', 'agriculture', 'transport'}

MAX_LOCATIONS = 4          # OA document URLs downloaded per unit (a BUDGET, not a fact)
THROTTLE_GIVEUP = 4        # consecutive 429s on a host -> stop calling it (circuit breaker)


# ═════════════════════════════════════════════════════════════════════════════════════
# 0. small helpers
# ═════════════════════════════════════════════════════════════════════════════════════

def norm_doi(x) -> str:
    if not x:
        return ''
    x = str(x).strip().lower()
    x = re.sub(r'^https?://(dx\.)?doi\.org/', '', x)
    x = re.sub(r'^doi:', '', x)
    return x.strip()


def norm_title(x) -> str:
    return re.sub(r'[^a-z0-9]+', ' ', str(x or '').lower()).strip()


def unit_key(doi: str, title: str) -> str:
    d = norm_doi(doi)
    if d:
        return 'doi:' + d
    t = norm_title(title)
    return 'title:' + t if t else ''


def log(msg: str) -> None:
    line = f'[{time.strftime("%H:%M:%S")}] {msg}'
    print(line, flush=True)
    with open(PROGRESS_LOG, 'a') as fh:
        fh.write(line + '\n')


# ═════════════════════════════════════════════════════════════════════════════════════
# 1. THE DEDUPED UNION
# ═════════════════════════════════════════════════════════════════════════════════════

def _add(units: dict, key: str, **fields):
    u = units.setdefault(key, {
        'unit_key': key, 'doi': '', 'title': '', 'venue': '', 'year': None,
        'authors': [], 'type': '', 'openalex_id': '', 'cells': set(), 'scouts': set(),
        'roles': set(), 'genai_specific': False, 'cited_by': 0, 'n_seed_links': 0,
        'is_oa_hint': False, 'admissible': True, 'why': [],
    })
    for k, v in fields.items():
        if v in (None, '', [], set()):
            continue
        if k in ('cells', 'scouts', 'roles'):
            u[k] |= set(v if isinstance(v, (set, list, tuple)) else [v])
        elif k == 'cited_by':
            u['cited_by'] = max(u['cited_by'], int(v or 0))
        elif k == 'n_seed_links':
            u['n_seed_links'] = max(u['n_seed_links'], int(v or 0))
        elif k in ('genai_specific', 'is_oa_hint'):
            u[k] = u[k] or bool(v)
        elif k == 'admissible':
            u[k] = u[k] and bool(v)                 # any scout flagging inadmissible wins
        elif k == 'why':
            u['why'].append(str(v)[:220])
        elif k == 'authors':
            if len(v) > len(u['authors']):
                u['authors'] = list(v)
        elif not u.get(k):
            u[k] = v
    return u


def build_union() -> dict:
    units: dict = {}

    # -- modality 1: citation-graph expansion --------------------------------------------
    for r in json.loads(M1.read_text()):
        k = unit_key(r.get('doi'), r.get('title'))
        if not k:
            continue
        cells = set(r.get('coverage_cells') or [])
        if r.get('primary_cell'):
            cells.add(r['primary_cell'])
        _add(units, k, doi=norm_doi(r.get('doi')), title=r.get('title'), venue=r.get('venue'),
             year=r.get('year'), type=r.get('type') or 'journal-article',
             openalex_id=(r.get('openalex_id') or '').replace('https://openalex.org/', ''),
             cells=cells, scouts='m1_citation_graph', cited_by=r.get('cited_by_count'),
             n_seed_links=r.get('n_seed_links'), why=r.get('why_relevant'))

    # -- modality 2: empty industry cells (journal hits only; leads are non-journal) -----
    m2 = json.loads(M2.read_text())
    for r in m2.get('hits', []):
        k = unit_key(r.get('doi'), r.get('title'))
        if not k:
            continue
        cells = {r.get('cell_served')} | set(r.get('also_serves') or [])
        _add(units, k, doi=norm_doi(r.get('doi')), title=r.get('title'), venue=r.get('venue'),
             year=r.get('year'), type='journal-article', authors=r.get('authors') or [],
             cells={c for c in cells if c}, scouts='m2_empty_cells',
             cited_by=r.get('cited_by'), is_oa_hint=r.get('is_oa'), why=r.get('why_relevant'))

    # -- modality 3: 2023-2025 frontier --------------------------------------------------
    m3 = json.loads(M3.read_text())
    for r in m3.get('records', []):
        k = unit_key(r.get('doi'), r.get('title'))
        if not k:
            continue
        cell = r.get('cell_served')
        _add(units, k, doi=norm_doi(r.get('doi')), title=r.get('title'), venue=r.get('venue'),
             year=r.get('year'), type='journal-article',
             cells={cell} if cell else set(), scouts='m3_frontier',
             genai_specific=r.get('genai_specific'), why=r.get('why_relevant'))

    # -- modality 4: hand-verified canon / contrasts -------------------------------------
    m4 = json.loads(M4.read_text())
    for r in m4.get('candidates', []):
        k = unit_key(r.get('doi'), r.get('title'))
        if not k:
            continue
        auth = r.get('authors')
        auth = [a.strip() for a in re.split(r'[;]', auth)] if isinstance(auth, str) else (auth or [])
        _add(units, k, doi=norm_doi(r.get('doi')), title=r.get('title'), venue=r.get('venue'),
             year=r.get('year'), type=('journal-article' if r.get('type') == 'journal' else r.get('type')),
             authors=auth, scouts='m4_canon', roles=r.get('role'),
             admissible=r.get('admissible_task72', True), why=r.get('why_relevant'))

    return units


# ═════════════════════════════════════════════════════════════════════════════════════
# 2. OFFLINE OA HARVEST — read OpenAlex OA pdf URLs straight out of pool_meta.jsonl.
#    Zero network cost for the whole modality-1 pool: maximally polite.
# ═════════════════════════════════════════════════════════════════════════════════════

def harvest_offline_oa(units: dict) -> dict:
    want_oaid = {u['openalex_id'] for u in units.values() if u['openalex_id']}
    want_doi = {norm_doi(u['doi']) for u in units.values() if u['doi']}
    oa: dict = {}                                    # unit lookup-id -> {'pdf':[...], 'landing':[...]}
    if not POOL_META.exists():
        return oa
    n = 0
    with open(POOL_META) as fh:
        for line in fh:
            n += 1
            try:
                d = json.loads(line)
            except Exception:
                continue
            oaid = (d.get('id') or '').replace('https://openalex.org/', '')
            doi = norm_doi(d.get('doi'))
            if oaid not in want_oaid and doi not in want_doi:
                continue
            pdfs, landings = [], []
            best = d.get('best_oa_location') or {}
            if best.get('pdf_url'):
                pdfs.append(best['pdf_url'])
            if best.get('landing_page_url'):
                landings.append(best['landing_page_url'])
            for loc in (d.get('locations') or []):
                if not loc.get('is_oa'):
                    continue
                if loc.get('pdf_url'):
                    pdfs.append(loc['pdf_url'])
                elif loc.get('landing_page_url'):
                    landings.append(loc['landing_page_url'])
            rec = {'pdf': list(dict.fromkeys(pdfs)), 'landing': list(dict.fromkeys(landings))}
            if oaid:
                oa[oaid] = rec
            if doi:
                oa['doi:' + doi] = rec
    log(f'offline OA harvest: scanned {n:,} pool_meta records; '
        f'{len(oa):,} lookup keys with OA locations')
    return oa


def offline_urls_for(u: dict, oa: dict) -> list[str]:
    rec = oa.get(u['openalex_id']) or oa.get('doi:' + norm_doi(u['doi'])) or {}
    return list(dict.fromkeys((rec.get('pdf') or []) + (rec.get('landing') or [])))


# ═════════════════════════════════════════════════════════════════════════════════════
# 3. PRIORITY — a transparent VIEW, in weighting.py's spirit (UNKNOWN != 0; fame is a
#    weak, capped tie-break, never the key). Empty cells + frontier + canon first.
# ═════════════════════════════════════════════════════════════════════════════════════

def recency_score(year) -> float:
    try:
        y = int(year)
    except (TypeError, ValueError):
        return 0.40                                  # UNKNOWN year -> neutral, NOT 0
    if y >= 2024:
        return 1.0
    if y == 2023:
        return 0.9
    if y >= 2020:
        return 0.6
    if y >= 2015:
        return 0.4
    return 0.25


def priority_of(u: dict) -> dict:
    has_empty = bool(u['cells'] & EMPTY_CELLS)
    is_canon = bool(u['roles'])
    genai = u['genai_specific']
    yr_recent = (u['year'] or 0) and int(u['year']) >= 2023

    # TIER — coverage-critical first. This is the "empty cells first" instruction, explicit.
    if has_empty or is_canon or genai:
        tier = 0
    elif yr_recent:
        tier = 1
    else:
        tier = 2

    cell_priority = 1.0 if has_empty else (0.7 if is_canon else 0.4)
    recency = recency_score(u['year'])
    graph_centrality = min(u['n_seed_links'], 5) / 5.0 if u['n_seed_links'] else 0.5
    fame = min(1.0, math.log10((u['cited_by'] or 0) + 1) / 4.0)   # weak, capped, log-scaled

    score = (0.40 * cell_priority + 0.25 * recency + 0.15 * graph_centrality
             + 0.10 * (1.0 if genai else 0.0) + 0.10 * fame)
    return {'tier': tier, 'score': round(score, 4),
            'cell_priority': cell_priority, 'recency': recency,
            'graph_centrality': round(graph_centrality, 3), 'fame_tiebreak': round(fame, 3),
            'has_empty_cell': has_empty, 'is_canon': is_canon}


def rank(units: dict) -> list[dict]:
    rows = []
    for u in units.values():
        p = priority_of(u)
        r = dict(u)
        r['cells'] = sorted(u['cells'])
        r['scouts'] = sorted(u['scouts'])
        r['roles'] = sorted(u['roles'])
        r['priority'] = p
        rows.append(r)
    rows.sort(key=lambda r: (r['priority']['tier'], -r['priority']['score'],
                             -(r['cited_by'] or 0)))
    return rows


# ═════════════════════════════════════════════════════════════════════════════════════
# 4. LOCATION DISCOVERY — try EVERY OA route. Each backend goes through the Acquirer, so
#    a 429 is on the ledger as THROTTLED, never as "no copy".
# ═════════════════════════════════════════════════════════════════════════════════════

class Hosts:
    """Per-host circuit breaker: stop calling a host after THROTTLE_GIVEUP consecutive
    429s. Skipping a throttled host is a BUDGET decision (recorded), not an absence."""
    def __init__(self):
        self.consec: dict = {}
        self.cool: set = set()

    def note(self, host: str, outcome: str):
        if outcome == BACKEND_FAILED:
            self.consec[host] = self.consec.get(host, 0) + 1
            if self.consec[host] >= THROTTLE_GIVEUP:
                self.cool.add(host)
        elif outcome in (RESPONDED, NOT_INDEXED):
            self.consec[host] = 0

    def hot(self, host: str) -> bool:
        return host not in self.cool


def _europepmc_urls(acq, unit, doi, hosts) -> list[str]:
    host = 'europepmc'
    if not hosts.hot(host):
        return []
    q = f'DOI:%22{urllib.parse.quote(doi)}%22'
    url = (f'https://www.ebi.ac.uk/europepmc/webservices/rest/search?query={q}'
           f'&format=json&resultType=core&pageSize=1')
    r, data = acq.get_json(unit, host, url, tries=2)
    hosts.note(host, derive_backend_outcome(acq.ledger.events(unit), host))
    urls = []
    try:
        res = (data.get('resultList') or {}).get('result') or []
        if res:
            rec = res[0]
            pmcid = rec.get('pmcid')
            if pmcid:
                fx = (f'https://www.ebi.ac.uk/europepmc/webservices/rest/'
                      f'{pmcid}/fullTextXML')
                urls.append(fx)
                acq.candidate(unit, host, fx, host_type='pmc_fulltext_xml')
            for fu in ((rec.get('fullTextUrlList') or {}).get('fullTextUrl') or []):
                if fu.get('availability', '').lower().startswith('open') and fu.get('url'):
                    urls.append(fu['url'])
                    acq.candidate(unit, host, fu['url'],
                                  host_type=str(fu.get('documentStyle') or ''))
    except Exception:
        pass
    return list(dict.fromkeys(urls))


def _doaj_urls(acq, unit, doi, hosts) -> list[str]:
    host = 'doaj'
    if not hosts.hot(host):
        return []
    url = f'https://doaj.org/api/search/articles/doi:{urllib.parse.quote(doi)}'
    r, data = acq.get_json(unit, host, url, tries=2)
    hosts.note(host, derive_backend_outcome(acq.ledger.events(unit), host))
    urls = []
    try:
        for res in (data.get('results') or [])[:1]:
            for lk in ((res.get('bibjson') or {}).get('link') or []):
                if lk.get('url') and lk.get('type', '') in ('fulltext', ''):
                    urls.append(lk['url'])
                    acq.candidate(unit, host, lk['url'], host_type=str(lk.get('type') or ''))
    except Exception:
        pass
    return list(dict.fromkeys(urls))


def _openalex_urls(acq, unit, doi, hosts) -> list[str]:
    host = 'openalex'
    if not hosts.hot(host):
        return []
    url = f'https://api.openalex.org/works/doi:{urllib.parse.quote(doi)}?mailto={MAILTO}'
    r, data = acq.get_json(unit, host, url, tries=2)
    hosts.note(host, derive_backend_outcome(acq.ledger.events(unit), host))
    urls = []
    try:
        best = data.get('best_oa_location') or {}
        if best.get('pdf_url'):
            urls.append(best['pdf_url'])
        for loc in (data.get('locations') or []):
            if loc.get('is_oa') and loc.get('pdf_url'):
                urls.append(loc['pdf_url'])
        for u2 in urls:
            acq.candidate(unit, host, u2, host_type='openalex_oa')
    except Exception:
        pass
    return list(dict.fromkeys(urls))


def discover_locations(acq, unit, u, offline_oa, hosts, deep: bool) -> list[str]:
    """The cascade. `deep` adds Europe PMC / DOAJ / live OpenAlex for the priority tiers."""
    urls: list[str] = []
    urls += offline_urls_for(u, offline_oa)          # 1. offline OpenAlex (free)
    doi = norm_doi(u['doi'])
    if doi:
        # 2. Unpaywall — canonical OA aggregator; emits its own candidate/backend events.
        if hosts.hot('unpaywall'):
            try:
                urls += deep_fetch.all_oa_locations(acq, unit, doi)
            except Exception:
                pass
            hosts.note('unpaywall', derive_backend_outcome(acq.ledger.events(unit), 'unpaywall'))
        if deep:
            urls += _europepmc_urls(acq, unit, doi, hosts)    # 3. Europe PMC / PMC full text
            if not u['openalex_id']:
                urls += _openalex_urls(acq, unit, doi, hosts)  # 4. live OpenAlex (if not offline)
            urls += _doaj_urls(acq, unit, doi, hosts)          # 5. DOAJ
    # de-dup, keep order (offline pdfs first)
    seen, out = set(), []
    for x in urls:
        if x and x not in seen:
            seen.add(x)
            out.append(x)
    return out


# ═════════════════════════════════════════════════════════════════════════════════════
# 5. PER-UNIT HONEST OUTCOME — a reducer over the ledger. THROTTLED stays distinct from
#    absence; a content result (fulltext/abstract/landing/wrong-work) beats a transport
#    failure for the primary label, but a throttle is flagged retriable regardless.
# ═════════════════════════════════════════════════════════════════════════════════════

def classify_unit(ledger, unit: str) -> dict:
    evs = ledger.events(unit)
    if not evs:
        return {'outcome': 'NOT_ATTEMPTED'}
    cls, info = derive_content_profile(evs)
    kind = info.get('artifact_kind', '')
    binding, _b = derive_semantic_binding(evs)
    route = derive_route_status(evs)
    outs = set(route.outcomes.values())
    throttled = BACKEND_FAILED in outs
    blocked = ACCESS_BLOCKED in outs

    if cls == C_FULLTEXT:
        outcome = 'FETCHED'
    elif binding == DIFFERENT_WORK or kind == 'wrong_work':
        outcome = 'WRONG_WORK'
    elif cls == C_ABSTRACT:
        outcome = 'ABSTRACT_ONLY'
    elif kind == 'landing_page':
        outcome = 'LANDING_PAGE'
    elif cls == C_UNREADABLE or kind == 'extraction_failure':
        outcome = 'UNREADABLE_ENCODING'
    else:
        # We hold nothing usable. The transport tells us WHY — and a throttle is retriable.
        if throttled:
            outcome = 'THROTTLED'
        elif blocked:
            outcome = 'ACCESS_DENIED'
        else:
            outcome = 'NOT_FOUND'
    return {
        'outcome': outcome,
        'content_class': cls,
        'artifact_kind': kind,
        'binding': binding,
        'route_state': route.state,
        'fulltext_retriable': bool(throttled and outcome != 'FETCHED'),
        'access_blocked_seen': blocked,
        'readable_words': info.get('readable_word_count') or info.get('word_count') or 0,
        'n_docs_held': info.get('n_documents_held', 1) if cls != C_CITATION else 0,
    }


# ═════════════════════════════════════════════════════════════════════════════════════
# 6. SUBCOMMANDS
