def cmd_build(args) -> int:
    units = build_union()
    n_doi = sum(1 for u in units.values() if u['doi'])
    log(f'UNION: {len(units):,} unique units ({n_doi:,} with DOI, '
        f'{len(units) - n_doi} title-only).')
    offline = harvest_offline_oa(units)
    ranked = rank(units)
    for r in ranked:
        r['offline_oa_urls'] = offline_urls_for(r, offline)

    # coverage census
    by_tier = {0: 0, 1: 0, 2: 0}
    by_cell = {c: 0 for c in EMPTY_CELLS}
    by_scout = {}
    n_offline = 0
    for r in ranked:
        by_tier[r['priority']['tier']] += 1
        for c in r['cells']:
            if c in by_cell:
                by_cell[c] += 1
        for s in r['scouts']:
            by_scout[s] = by_scout.get(s, 0) + 1
        if r['offline_oa_urls']:
            n_offline += 1

    UNION_OUT.write_text(json.dumps({
        'generated': time.strftime('%Y-%m-%dT%H:%M:%S'),
        'union_size': len(units),
        'with_doi': n_doi, 'title_only': len(units) - n_doi,
        'by_tier': by_tier, 'empty_cell_coverage': by_cell, 'by_scout': by_scout,
        'units_with_offline_oa_url': n_offline,
        'dedup_rule': 'normalized DOI, then normalized title where DOI is missing',
        'tiers': {'0': 'empty coverage cell OR canon/contrast OR generative-AI-specific',
                  '1': '2023-2025 frontier (remainder)',
                  '2': 'citation-graph expansion (general/labor cells)'},
    }, indent=1))
    RANKED_OUT.write_text(json.dumps(ranked, indent=1))
    log(f'tiers: T0(coverage-critical)={by_tier[0]:,}  T1(frontier)={by_tier[1]:,}  '
        f'T2(graph)={by_tier[2]:,}')
    log(f'empty-cell units: {by_cell}')
    log(f'units with an OFFLINE OA url (no network needed to find a copy): {n_offline:,}')
    log(f'wrote {UNION_OUT.name} and {RANKED_OUT.name}')
    return 0


def cmd_fetch(args) -> int:
    if not RANKED_OUT.exists():
        cmd_build(args)
    ranked = json.loads(RANKED_OUT.read_text())
    offline = {}                                     # already inlined into ranked rows

    tiers = {int(t) for t in str(args.tiers).split(',')} if args.tiers else {0, 1, 2}
    targets = [r for r in ranked if r['priority']['tier'] in tiers and r['admissible']]
    if args.sample:
        targets = targets[:args.sample]

    ledger = open_ledger(LEDGER)
    blobs = BlobStore(BLOBS)
    acq = Acquirer('bulk_fetch', ledger=ledger, blobs=blobs)
    hosts = Hosts()

    log(f'=== FETCH: {len(targets):,} target units (tiers {sorted(tiers)}), '
        f'budget: max_units={args.max_units}, wall_clock={args.wall_clock_mins}min ===')
    log(f'ledger={LEDGER}  ({len(ledger)} events already on record)  blobs={BLOBS}')

    t0 = time.time()
    deadline = t0 + args.wall_clock_mins * 60
    done = 0
    hist: dict = {}
    processed_keys = set()

    for i, r in enumerate(targets):
        if done >= args.max_units:
            log(f'-- MAX_UNITS budget ({args.max_units}) reached at target #{i}. Stopping. --')
            break
        if time.time() >= deadline:
            log(f'-- WALL_CLOCK budget ({args.wall_clock_mins}min) reached at target #{i}. '
                f'Stopping. --')
            break

        unit = r['unit_key']
        doi = norm_doi(r['doi'])
        deep = r['priority']['tier'] in (0, 1)       # richer route for the priority tiers

        # 1. ROUTE_PLANNED — named before we walk it, so route_complete can mean something.
        planned = ['unpaywall', 's2/abstract']
        if deep:
            planned += ['europepmc', 'doaj']
            if not r['openalex_id']:
                planned.append('openalex')
        acq.plan_route(unit, planned, requested_title=r['title'] or '', doi=doi,
                       requested_venue=r['venue'] or '', requested_year=r['year'],
                       source_type=r['type'] or 'journal-article')

        row = {'title': r['title'], 'authors': r['authors'], 'doi': doi,
               'venue': r['venue'], 'year': r['year'], 'type': r['type'] or 'journal-article'}

        # 2. discover OA locations across every route
        locs = discover_locations(acq, unit, r, offline, hosts, deep)

        # 3. fetch the bytes (content hosts are diverse -> the per-host spacing rarely bites)
        for url in locs[:MAX_LOCATIONS]:
            ch = content_host(url)
            if not hosts.hot(ch):
                continue
            try:
                deep_fetch.fetch_text(acq, unit, url, row)
            except Exception as e:
                log(f'   fetch error {unit}: {type(e).__name__}')
            hosts.note(ch, derive_backend_outcome(acq.ledger.events(unit), ch))
            # stop early if we already hold a complete document
            cls, _ = derive_content_profile(acq.ledger.events(unit))
            if cls == C_FULLTEXT:
                break
        if len(locs) > MAX_LOCATIONS:
            acq.budget_stopped(unit, n_locations_known=len(locs), n_locations_tried=MAX_LOCATIONS,
                               reason_text=f'tried {MAX_LOCATIONS} of {len(locs)} known OA locations')

        # 4. an abstract floor from Semantic Scholar (skipped if S2 is cooling)
        cls_now, _ = derive_content_profile(acq.ledger.events(unit))
        if cls_now != C_FULLTEXT and doi and hosts.hot('content:api.semanticscholar.org') \
                and hosts.hot('s2'):
            try:
                pdf = deep_fetch.semantic_scholar_pdf(acq, unit, doi)
                hosts.note('s2', derive_backend_outcome(acq.ledger.events(unit), 's2/oa-pdf'))
                if pdf and hosts.hot(content_host(pdf)):
                    deep_fetch.fetch_text(acq, unit, pdf, row)
            except Exception:
                pass

        outc = classify_unit(ledger, unit)
        hist[outc['outcome']] = hist.get(outc['outcome'], 0) + 1
        processed_keys.add(unit)
        done += 1

        tag = f"T{r['priority']['tier']}"
        cell = ','.join(sorted(set(r['cells']) & EMPTY_CELLS)) or '-'
        if done % 10 == 0 or outc['outcome'] == 'FETCHED':
            el = time.time() - t0
            log(f"  [{done:>4}/{len(targets)}] {tag} cell={cell:<12} "
                f"{outc['outcome']:<18} {outc.get('readable_words', 0):>6}w  "
                f"cool_hosts={len(hosts.cool)}  {el/60:.1f}min  {str(r['title'])[:44]}")

    # -- FINAL: derive outcomes over the WHOLE ledger, and log what we deferred ----------
    write_outcomes(ledger, ranked, processed_keys, hosts,
                   budget={'max_units': args.max_units, 'wall_clock_mins': args.wall_clock_mins,
                           'tiers': sorted(tiers), 'elapsed_min': round((time.time() - t0) / 60, 1)})
    return 0


def write_outcomes(ledger, ranked, processed_keys, hosts, budget) -> None:
    hist: dict = {}
    retriable = 0
    per_unit = []
    fetched_units = []
    for r in ranked:
        unit = r['unit_key']
        if unit not in processed_keys:
            continue
        c = classify_unit(ledger, unit)
        hist[c['outcome']] = hist.get(c['outcome'], 0) + 1
        if c.get('fulltext_retriable'):
            retriable += 1
        rec = {'unit_key': unit, 'doi': r['doi'], 'title': r['title'],
               'tier': r['priority']['tier'], 'cells': r['cells'], 'scouts': r['scouts'],
               **c}
        per_unit.append(rec)
        if c['outcome'] == 'FETCHED':
            fetched_units.append(rec)

    deferred = [{'unit_key': r['unit_key'], 'doi': r['doi'], 'title': r['title'],
                 'tier': r['priority']['tier'], 'cells': r['cells'],
                 'priority_score': r['priority']['score'],
                 'reason': 'below the budget cutoff in priority order — NOT an absence; retriable'}
                for r in ranked if r['unit_key'] not in processed_keys and r['admissible']]
    inadmissible = [{'unit_key': r['unit_key'], 'doi': r['doi'], 'title': r['title'],
                     'reason': 'flagged non-journal / inadmissible under task-72 journal-only policy'}
                    for r in ranked if not r['admissible']]

    # empty-cell yield: how many of the outline's blank cells did we actually close?
    cell_fetched = {c: 0 for c in EMPTY_CELLS}
    cell_total = {c: 0 for c in EMPTY_CELLS}
    for rec in per_unit:
        for c in rec['cells']:
            if c in cell_total:
                cell_total[c] += 1
                if rec['outcome'] == 'FETCHED':
                    cell_fetched[c] += 1

    OUTCOMES_OUT.write_text(json.dumps({
        'generated': time.strftime('%Y-%m-%dT%H:%M:%S'),
        'union_size': len(ranked),
        'attempted': len(processed_keys),
        'deferred': len(deferred),
        'inadmissible_excluded': len(inadmissible),
        'budget': budget,
        'outcome_histogram': dict(sorted(hist.items(), key=lambda x: -x[1])),
        'fetched_count': hist.get('FETCHED', 0),
        'throttled_retriable_note': (
            f'{hist.get("THROTTLED", 0)} units are THROTTLED (429/503) and '
            f'{retriable} more hold a partial doc whose full text is retriable — '
            f'a THROTTLED is NOT an absence; re-run to recover.'),
        'empty_cell_fetched': cell_fetched,
        'empty_cell_attempted': cell_total,
        'cooling_hosts': sorted(hosts.cool),
        'per_unit_outcomes': per_unit,
        'fetched_units': fetched_units,
        'deferred_units': deferred,
        'inadmissible_units': inadmissible,
    }, indent=1))
    log('=== OUTCOME HISTOGRAM (honest, derived from the ledger) ===')
    for k, v in sorted(hist.items(), key=lambda x: -x[1]):
        log(f'   {k:<20} {v:>5}')
    log(f'attempted={len(processed_keys)}  fetched={hist.get("FETCHED", 0)}  '
        f'deferred={len(deferred)}  throttled(retriable)={hist.get("THROTTLED", 0)}+{retriable}')
    log(f'empty-cell fulltext yield: {cell_fetched}')
    log(f'wrote {OUTCOMES_OUT.name}')


def cmd_report(args) -> int:
    ledger = open_ledger(LEDGER)
    ranked = json.loads(RANKED_OUT.read_text())
    processed = set(ledger.units())
    write_outcomes(ledger, ranked, processed, Hosts(),
                   budget={'note': 're-derived from the ledger post hoc'})
    return 0


def main() -> int:
    ap = argparse.ArgumentParser()
    sub = ap.add_subparsers(dest='cmd', required=True)
    sub.add_parser('build')
    pf = sub.add_parser('fetch')
    pf.add_argument('--max-units', type=int, default=600)
    pf.add_argument('--wall-clock-mins', type=float, default=45.0)
    pf.add_argument('--sample', type=int, default=0)
    pf.add_argument('--tiers', type=str, default='0,1,2')
    sub.add_parser('report')
    args = ap.parse_args()
    return {'build': cmd_build, 'fetch': cmd_fetch, 'report': cmd_report}[args.cmd](args)


if __name__ == '__main__':
    raise SystemExit(main())

